import{_ as s,o as a,c as n,V as l}from"./chunks/framework.24f0af87.js";const o="/mxcad_docs/assets/image-25.7b324f25.png",d=JSON.parse('{"title":"System Variables","description":"","frontmatter":{},"headers":[],"relativePath":"en/1.指南/6.系统变量.md","filePath":"en/1.指南/6.系统变量.md"}'),p={name:"en/1.指南/6.系统变量.md"},e=l('<h1 id="system-variables" tabindex="-1">System Variables <a class="header-anchor" href="#system-variables" aria-label="Permalink to &quot;System Variables&quot;">​</a></h1><p>CAD system variables are settings used in computer-aided design (CAD) software. CAD system variables can control the behavior, appearance, and functionality of CAD software. They can be global variables that control the behavior of the entire CAD system or local variables that affect specific CAD objects or operations.</p><p>CAD system variables can control various parameters, such as the units, precision, and colors of graphic display, default properties of drawing objects, layout of toolbars and menus, and the behavior of various commands. By modifying the values of system variables, users can customize the functionality and appearance of CAD software according to their needs.</p><p>Each CAD software has its own set of system variables, and new system variables can be added as needed. Users can modify the values of system variables by setting options in CAD software or using the corresponding commands.</p><p>MxCAD also provides methods for getting and setting CAD variables, based on the different variable types. There are four different methods for setting:</p><p>To get a floating-point variable: <a href="./../../api/classes/McObject.html#getsysvardouble">getSysVarDouble</a></p><p>To get a long integer variable: <a href="./../../api/classes/McObject.html#getSysVarLong">getSysVarLong</a></p><p>To get a point variable: <a href="./../../api/classes/McObject.html#getSysVarLong">getSysVarPoint</a></p><p>To get a string variable: <a href="./../../api/classes/McObject.html#getSysVarString">getSysVarString</a></p><p>To set a variable, you just need to replace &quot;get&quot; with &quot;set&quot; in the method name and provide the variable name and the corresponding value of the appropriate type.</p><h2 id="dynamic-snap-related-system-variables" tabindex="-1">Dynamic Snap Related System Variables <a class="header-anchor" href="#dynamic-snap-related-system-variables" aria-label="Permalink to &quot;Dynamic Snap Related System Variables&quot;">​</a></h2><p>Let&#39;s illustrate the use of system variables with an example:</p><p>Sample project: <a href="https://demo.mxdraw3d.com:3000/mxcad/" target="_blank" rel="noreferrer">https://demo.mxdraw3d.com:3000/mxcad/</a></p><p>In the bottom-right corner of the project, there are buttons that control various snap settings. These buttons are all long integer system variables:</p><p><img src="'+o+`" alt="Alt text"></p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">enum</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">SysVarLongSketchSettings</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Grid Mode */</span></span>
<span class="line"><span style="color:#A6ACCD;">  GRIDMODE </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Grid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Ortho Mode */</span></span>
<span class="line"><span style="color:#A6ACCD;">  ORTHOMODE </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Ortho</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Polar Mode */</span></span>
<span class="line"><span style="color:#A6ACCD;">  AUTOSNAP </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Polar</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Object Snap Mode */</span></span>
<span class="line"><span style="color:#A6ACCD;">  OSMODE </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Object Snap</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Object Tracking Mode */</span></span>
<span class="line"><span style="color:#A6ACCD;">  DYNTRACE </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Object Tracking</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Dynamic Input Mode */</span></span>
<span class="line"><span style="color:#A6ACCD;">  DYNINPUT </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Dynamic Input</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Lineweight Display Mode */</span></span>
<span class="line"><span style="color:#A6ACCD;">  LWDISPLAY </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Lineweight Display</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>Except for the <code>OSMODE</code> object snap variable, the values for the other variables are <code>0</code> to indicate they are turned off, and <code>1</code> to indicate they are turned on.</p><p>You can set these variables using the following code:</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">MxCpp</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">mxcad</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> mxcad </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> MxCpp</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getCurrentMxCAD</span><span style="color:#A6ACCD;">()</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Turn on grid mode</span></span>
<span class="line"><span style="color:#A6ACCD;">mxcad</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">setSysVarLong</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">GRIDMODE</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">1</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Turn on ortho mode</span></span>
<span class="line"><span style="color:#A6ACCD;">mxcad</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">setSysVarLong</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">ORTHOMODE</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">1</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Turn off lineweight display</span></span>
<span class="line"><span style="color:#A6ACCD;">mxcad</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">setSysVarLong</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">LWDISPLAY</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#A6ACCD;">)</span></span></code></pre></div><p>For dynamic snap, there are multiple snap options, and the value you get is a result of bitwise operations on these options to determine which snaps are enabled or disabled. Therefore, you need to set dynamic snap settings by adjusting various snap switches. Here is an example for dynamic object snap settings:</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">MxCpp</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">mxcad</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> mxcad </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> MxCpp</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getCurrentMxCAD</span><span style="color:#A6ACCD;">()</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> osModeVal </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> mxcad</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">setSysVarLong</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">OSMODE</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">enum</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">SysVarLongSketchSettingsOsMode</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Endpoint Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  End </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Midpoint Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Mid </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">2</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Center Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Cen </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">4</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Node Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Node </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">8</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Quadrant Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Quad </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">16</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Intersection Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Int </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">32</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Insertion Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Ins </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">64</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Perpendicular Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Perp </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">128</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Tangent Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Tan </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">256</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Nearest Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Near </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">512</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Apparent Intersection Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  App </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">2048</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Extension Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Ext </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">4096</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Parallel Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Par </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">8192</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">/** Turn Off Snap */</span></span>
<span class="line"><span style="color:#A6ACCD;">  Off </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">16384</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Check if Object Snap is turned off (0 or 1)</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> osModeOff </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> osModeVal </span><span style="color:#89DDFF;">&amp;</span><span style="color:#A6ACCD;"> SysVarLongSketchSettingsOsMode</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Off</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Check if Parallel Snap is turned on (0 or 8192)</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> osModePar </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> osModeVal </span><span style="color:#89DDFF;">&amp;</span><span style="color:#A6ACCD;"> SysVarLongSketchSettingsOsMode</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Par</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Set whether Parallel Snap is turned on</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> isOpenOsModePar </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#FF9CAC;">true</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Set the value accordingly</span></span>
<span class="line"><span style="color:#A6ACCD;">mxcad</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">setSysVarLong</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">OSMODE</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"><span style="color:#A6ACCD;">    isOpenOsModePar </span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">?</span></span>
<span class="line"><span style="color:#A6ACCD;">    (osModeVal </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> SysVarLongSketchSettingsOsMode</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Par) </span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#A6ACCD;">    (osModeVal </span><span style="color:#89DDFF;">&amp;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">~</span><span style="color:#A6ACCD;">SysVarLongSketchSettingsOsMode</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Par)</span></span>
<span class="line"><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// You can use similar code for other snap settings as well.</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// ...</span></span></code></pre></div><p>With the above code, you can customize various CAD system variables based on specific rules. CAD software offers a wide range of variables, and you can adjust them using the provided methods in MxCAD.</p>`,22),t=[e];function c(r,y,D,i,C,A){return a(),n("div",null,t)}const f=s(p,[["render",c]]);export{d as __pageData,f as default};
